with open(GEN) as f:
    content = f.read()

# Find the ta stub block and replace it
# Pattern: "ta": {"tag": "…", ... , "label": "தமிழ்"}
ta_stub = re.search(r'"ta":\s*\{[^}]*"[^}]*\}', content)
if not ta_stub:
    print("Could not find ta stub")
    exit(1)

# Build the replacement ta entry
ta_entry = json.dumps(TA_TRANS, ensure_ascii=False, indent=None)
# Remove surrounding braces from the json dump since we need "ta": { ... }
ta_replacement = f'"ta": {ta_entry}'

old_ta = ta_stub.group()
content = content.replace(old_ta, ta_replacement, 1)

with open(GEN, 'w') as f:
    f.write(content)

# Verify
with open(GEN) as f:
    verified = f.read()

if '"…"' not in verified.split('"ta":')[1].split('"gu":')[0]:
    print("✅ Tamil translations verified — no stubs remaining")
else:
    print("❌ Stubs still present")

print(f"File size: {len(verified)} bytes")

# Count keys in ta section
ta_section = verified.split('"ta":')[1].split('"gu":')[0]
key_count = ta_section.count('"')
print(f"Tamil section has approximately {key_count} key-value pairs")
